import { useState, useEffect } from "react";
import API from "../api/axios";

const CategoryMaster = () => {
  const [examId, setExamId] = useState("");
  const [categoryName, setCategoryName] = useState("");
  const [exams, setExams] = useState([]);
  const [categories, setCategories] = useState([]);

  useEffect(() => {
    fetchExams();
    fetchCategories();
  }, []);

  const fetchExams = async () => {
    const { data } = await API.get("/exam");
    setExams(data);
  };

  const fetchCategories = async () => {
    const { data } = await API.get("/category");
    setCategories(data);
  };

  const submit = async () => {
    await API.post("/category", { examId, categoryName });
    fetchCategories();
  };

  return (
    <div>
      <h2 className="text-2xl font-bold mb-4">Category Master</h2>

      <div className="bg-white p-4 rounded shadow mb-6 space-y-3">
        <select
          className="border p-2 w-full"
          onChange={(e) => setExamId(e.target.value)}
        >
          <option>Select Exam</option>
          {exams.map(e => (
            <option key={e._id} value={e._id}>{e.examName}</option>
          ))}
        </select>

        <input
          className="border p-2 w-full"
          placeholder="Category Name"
          onChange={(e) => setCategoryName(e.target.value)}
        />

        <button
          onClick={submit}
          className="bg-indigo-600 text-white px-4 py-2 rounded"
        >
          Add Category
        </button>
      </div>

      {categories.map(c => (
        <div key={c._id} className="bg-gray-100 p-3 mb-2 rounded">
          {c.categoryName} ({c.categoryCode})
        </div>
      ))}
    </div>
  );
};

export default CategoryMaster;
